const W=Math.min(innerWidth,480),H=innerHeight;class S extends Phaser.Scene{create(){this.add.rectangle(W/2,H/2,W,H,0x132016);this.f=this.add.circle(W/2,H-30,10,0x86efac);this.physics.add.existing(this.f);this.cars=this.physics.add.group();this.c=this.input.keyboard.createCursorKeys();this.r=this.input.keyboard.addKey('R');for(let i=0;i<5;i++)this.time.addEvent({delay:700+i*120,loop:true,callback:()=>{const y=120+i*70;const car=this.add.rectangle(-20,y,38,18,0xf87171);this.physics.add.existing(car);car.body.setVelocityX(140+i*20);this.cars.add(car);}});this.physics.add.overlap(this.f,this.cars,()=>this.end('HIT'));}hop(dx,dy){this.f.x=Phaser.Math.Clamp(this.f.x+dx*36,20,W-20);this.f.y=Phaser.Math.Clamp(this.f.y+dy*36,20,H-20);if(this.f.y<40)this.end('CLEAR');}end(m){if(this.over)return;this.over=true;this.add.text(W/2,H/2,m+'\nR',{align:'center'}).setOrigin(.5);}update(){if(this.r.isDown)this.scene.restart();if(this.over)return;if(Phaser.Input.Keyboard.JustDown(this.c.left))this.hop(-1,0);if(Phaser.Input.Keyboard.JustDown(this.c.right))this.hop(1,0);if(Phaser.Input.Keyboard.JustDown(this.c.up))this.hop(0,-1);if(Phaser.Input.Keyboard.JustDown(this.c.down))this.hop(0,1);this.cars.getChildren().forEach(c=>{if(c.x>W+40)c.x=-40;});}}
new Phaser.Game({type:Phaser.AUTO,parent:'game',width:W,height:H,physics:{default:'arcade'},scene:[S]});
